using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Set up options with the default reflection-based resolver
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1️⃣  Strongly-typed metadata retrieval — returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personMeta = options.GetTypeInfo<Person>();
Console.WriteLine($"Got typed metadata for: {personMeta.Type.Name}");
Console.WriteLine($"  Kind       : {personMeta.Kind}");
Console.WriteLine($"  Properties : {personMeta.Properties.Count}");

// 2️⃣  Probe without throwing — TryGetTypeInfo returns false if unavailable
bool found = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info);
Console.WriteLine($"\nTryGetTypeInfo(Person)  → found={found}, type={info?.Type.Name}");

// Try a type the resolver *can't* handle (use options with no resolver)
var empty = new JsonSerializerOptions { TypeInfoResolver = null };
bool notFound = empty.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? missing);
Console.WriteLine($"TryGetTypeInfo(Person) [no resolver] → found={notFound}, info={missing?.ToString() ?? "null"}");

public record Person(string Name, int Age);

